features.snippet:
input [8:0] A;
input [1:0] B;
output [2:0] Y;
$shiftx #(
  .A_WIDTH(9), .B_WIDTH(4),
  .Y_WIDTH(3),
  .A_SIGNED(1'b0), .B_SIGNED(1'b0)
) cel (
  .A(A), .B({B, 2'h0}), .Y(Y)
);

logic [8:0] A;
logic [1:0] B;
logic [2:0] Y;
assign Y = A >> {B, 2'h0};

logic [8:0] A;
logic [1:0] B;
logic [2:0] Y;
assign Y = A[{B, 2'h0} +: 3];
